"""pycparser.c_parser — minimal C parser for cffi on iOS."""

from pycparser import c_ast
import re


class ParseError(Exception):
    pass


class CParser:
    """Minimal C declaration parser for cffi compatibility.

    Handles: typedef, struct/union/enum declarations, function prototypes,
    variable declarations, pointer types, array types, const/volatile qualifiers.
    Does NOT handle: full C expressions, function bodies, preprocessor directives.
    """

    def __init__(self):
        self._typedefs = set()

    def parse(self, text, filename='<input>', debuglevel=0):
        """Parse C declarations and return a FileAST."""
        # Strip comments
        text = re.sub(r'/\*.*?\*/', ' ', text, flags=re.DOTALL)
        text = re.sub(r'//[^\n]*', '', text)
        # Strip preprocessor lines
        text = re.sub(r'^\s*#[^\n]*$', '', text, flags=re.MULTILINE)

        ext = []
        # Split on semicolons (very simplified)
        for stmt in self._split_declarations(text):
            stmt = stmt.strip()
            if not stmt:
                continue
            try:
                node = self._parse_declaration(stmt)
                if node is not None:
                    ext.append(node)
            except Exception:
                # Skip unparseable declarations
                pass
        return c_ast.FileAST(ext=ext)

    def _split_declarations(self, text):
        """Split text into declaration strings at top-level semicolons and closing braces."""
        result = []
        depth = 0
        current = []
        for ch in text:
            if ch == '{':
                depth += 1
                current.append(ch)
            elif ch == '}':
                depth -= 1
                current.append(ch)
                if depth == 0:
                    # Consume optional semicolon
                    result.append(''.join(current))
                    current = []
            elif ch == ';' and depth == 0:
                result.append(''.join(current))
                current = []
            else:
                current.append(ch)
        if current:
            result.append(''.join(current))
        return result

    def _parse_declaration(self, text):
        """Parse a single declaration into an AST node."""
        text = text.strip().rstrip(';').strip()
        if not text:
            return None

        # typedef
        if text.startswith('typedef'):
            return self._parse_typedef(text)

        # struct/union/enum with body
        for keyword in ('struct', 'union', 'enum'):
            if text.startswith(keyword):
                return self._parse_aggregate(text, keyword)

        # Function prototype or variable declaration
        return self._parse_decl(text)

    def _parse_typedef(self, text):
        text = text[len('typedef'):].strip()
        # Very simplified: last word is the alias name
        parts = text.rsplit(None, 1)
        if len(parts) == 2:
            name = parts[1].rstrip('*').strip()
            self._typedefs.add(name)
            type_node = c_ast.TypeDecl(
                declname=name, quals=[],
                type=c_ast.IdentifierType(names=parts[0].split())
            )
            return c_ast.Typedef(name=name, quals=[], storage=['typedef'], type=type_node)
        return None

    def _parse_aggregate(self, text, keyword):
        # Extract name
        rest = text[len(keyword):].strip()
        name = None
        if rest and rest[0] != '{':
            name_match = re.match(r'(\w+)', rest)
            if name_match:
                name = name_match.group(1)
                rest = rest[len(name):].strip()

        if keyword == 'struct':
            return c_ast.Struct(name=name, decls=[])
        elif keyword == 'union':
            return c_ast.Union(name=name, decls=[])
        elif keyword == 'enum':
            return c_ast.Enum(name=name, values=None)
        return None

    def _parse_decl(self, text):
        """Parse a variable/function declaration."""
        text = text.strip()
        if not text:
            return None

        # Check for function: contains '('
        paren = text.find('(')
        if paren > 0 and not text.startswith('('):
            # Likely a function declaration
            before = text[:paren].strip()
            parts = before.rsplit(None, 1)
            if len(parts) >= 2:
                name = parts[-1].lstrip('*')
                ret_type = parts[0]
                type_node = c_ast.FuncDecl(
                    args=c_ast.ParamList(params=[]),
                    type=c_ast.TypeDecl(
                        declname=name, quals=[],
                        type=c_ast.IdentifierType(names=ret_type.split())
                    )
                )
                return c_ast.Decl(name=name, type=type_node)

        # Variable declaration
        parts = text.rsplit(None, 1)
        if len(parts) >= 2:
            name = parts[-1].lstrip('*').rstrip('[]')
            type_names = parts[0].split()
            type_node = c_ast.TypeDecl(
                declname=name, quals=[],
                type=c_ast.IdentifierType(names=type_names)
            )
            # Pointer
            if '*' in parts[-1] or '*' in parts[0]:
                type_node = c_ast.PtrDecl(quals=[], type=type_node)
            # Array
            if parts[-1].endswith(']'):
                type_node = c_ast.ArrayDecl(type=type_node, dim=None)
            return c_ast.Decl(name=name, type=type_node)

        return None
